void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "First time":			dialog.text = StringFromKey("MarkLevua_1");			link.l1 = StringFromKey("MarkLevua_2");			link.l1.go = "1";		break;		case "1":			dialog.text = StringFromKey("MarkLevua_3");			link.l1 = StringFromKey("MarkLevua_4");			link.l1.go = "2";		break;		case "2":			dialog.text = StringFromKey("MarkLevua_5");			link.l1 = StringFromKey("MarkLevua_6");			link.l1.go = "exit";			NextDiag.TempNode = "4";			locCameraSleep(true);		break;		case "4":			dialog.text = StringFromKey("MarkLevua_7");			link.l1 = StringFromKey("MarkLevua_8");			link.l1.go = "5";			locCameraSleep(false);		break;		case "5":			dialog.text = StringFromKey("MarkLevua_9");			link.l1 = StringFromKey("MarkLevua_10");			link.l1.go = "exit";			NextDiag.TempNode = "6";		break;		case "6":			dialog.text = StringFromKey("MarkLevua_11");			link.l1 = StringFromKey("MarkLevua_12");			link.l1.go = "7";		break;		case "7":			dialog.text = StringFromKey("MarkLevua_13");			link.l1 = "...";			link.l1.go = "exit";			AddDialogExitQuest("MainHeroFightModeOn");			NextDiag.TempNode = "8";		break;		case "":			dialog.text = "";			link.l1 = "";			link.l1.go = "";		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}